## Implementation Approach

I'll implement an Emitter/Event pattern to replace direct function calls with an event-based system. This pattern allows components to communicate without tight coupling by having an emitter that broadcasts events and listeners that subscribe to those events.

```typescript
// Basic Event Emitter implementation
class EventEmitter {
  private listeners: Record<string, Function[]> = {};

  on(event: string, callback: Function): void {
    if (!this.listeners[event]) {
      this.listeners[event] = [];
    }
    this.listeners[event].push(callback);
  }

  off(event: string, callback: Function): void {
    if (!this.listeners[event]) return;
    this.listeners[event] = this.listeners[event].filter(cb => cb !== callback);
  }

  emit(event: string, ...args: any[]): void {
    if (!this.listeners[event]) return;
    this.listeners[event].forEach(callback => {
      callback(...args);
    });
  }
}

// Example usage
const emitter = new EventEmitter();

// Component A (publisher)
function componentA() {
  // Instead of directly calling componentB.handleData(data)
  emitter.emit('data-updated', { value: 42 });
}

// Component B (subscriber)
function componentB() {
  emitter.on('data-updated', (data) => {
    console.log('Received data:', data);
  });
}
```

